import WebPageHeaderInfo from './components/WebPageHeaderInfo';
import WebPageNavigationHeader from './components/WebPageNavigationHeader';
import './style.css';

const WebPageHeader = () => {
    return (
        <header>
            <WebPageHeaderInfo currentPageName="Home"
                domainNameTextColor="blue"
                currentPageNameTextColor="blue"
                backgroundColor="grey"
                githubURL="www.github.com"
                githubPagesURL="www.github.com"
                githubPagesTextColor="blue"
                domainName="www.unix69.github.io"
            />
            <WebPageNavigationHeader/>
        </header>
    );
};

export default WebPageHeader;
